sys_transform_script.script:
(function runTransformScript(source, target, map, log, isUpdate) {
  var utils = new AlationUtils();

  // Always set correlation_id from external id
  var ext = String(source.u_external_incident_id || '').trim();
  if (ext) target.correlation_id = ext;

  // Basic fields
  var summary = String(source.u_summary || '').trim();
  if (summary) target.short_description = summary;

  if (source.u_description != null) target.description = String(source.u_description);

  // Resolve Impact/Urgency (store raw in staging; resolve here)
  var impactVal  = utils.resolveImpactValue(source.u_impact);
  var urgencyVal = utils.resolveUrgencyValue(source.u_urgency);
  if (impactVal)  target.impact  = impactVal;
  if (urgencyVal) target.urgency = urgencyVal;

  // Priority (you already resolve in utils for task/incident; do it similarly if needed)
  var pr = utils.resolvePriorityValue(source.u_priority);
  if (pr) target.priority = pr;

  // Category/Subcategory
  var catVal = utils.resolveCategoryValue(source.u_category);
  if (catVal) target.category = catVal;

  var subVal = utils.resolveSubcategoryValue(catVal || '', source.u_subcategory);
  if (subVal) target.subcategory = subVal;

  // Optional state
  var sv = utils.resolveStateValue(source.u_state);
  if (sv) target.state = sv;

  // Assignment group (sys_id or name)
  var grpIn = String(source.u_assignment_group || '').trim();
  if (grpIn) {
    var groupRec = new GlideRecord('sys_user_group');
    if (groupRec.get(grpIn)) {
      target.assignment_group = groupRec.sys_id;
    } else {
      groupRec.addQuery('name', grpIn);
      groupRec.setLimit(1);
      groupRec.query();
      if (groupRec.next()) target.assignment_group = groupRec.sys_id;
    }
  }

  // Assignee (sys_id or user_name)
  var assigneeIn = String(source.u_assigned_to || '').trim();
  if (assigneeIn) {
    var userRec = new GlideRecord('sys_user');
    if (userRec.get(assigneeIn)) {
      target.assigned_to = userRec.sys_id;
    } else {
      userRec.addQuery('user_name', assigneeIn);
      userRec.setLimit(1);
      userRec.query();
      if (userRec.next()) target.assigned_to = userRec.sys_id;
    }
  }

})(source, target, map, log, action === "update");
